fn solve(n: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let num_nodes = n as usize;

    // Helper function for O(N^2) Dijkstra implementation
    // Since std imports are disallowed, we use the simpler O(N^2) approach instead of using a heap.
    fn dijkstra_n2(n_nodes: usize, adj: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
        // INF must be larger than the maximum possible path cost (approx 2*10^14)
        const INF: i64 = 4_000_000_000_000_000_000; 

        let mut dist = vec![INF; n_nodes];
        let mut visited = vec![false; n_nodes];

        dist[start_node] = 0;

        for _ in 0..n_nodes {
            // Find unvisited node u with minimum distance (O(N) scan)
            let mut u = n_nodes;
            let mut min_dist = INF;

            for i in 0..n_nodes {
                if !visited[i] && dist[i] < min_dist {
                    min_dist = dist[i];
                    u = i;
                }
            }

            if u == n_nodes {
                break; // All reachable nodes visited
            }

            visited[u] = true;

            // Relax edges from u
            for &(v, weight) in &adj[u] {
                if !visited[v] {
                    // Check if distance through u is shorter
                    if dist[u] != INF {
                        let new_dist = dist[u].saturating_add(weight);
                        if new_dist < dist[v] {
                            dist[v] = new_dist;
                        }
                    }
                }
            }
        }

        dist
    }

    // 1. Build adjacency lists for Empty Travel (G_empty) and Carrying Travel (G_carry)

    let mut adj_empty: Vec<Vec<(usize, i64)>> = vec![Vec::new(); num_nodes];
    let mut adj_carry: Vec<Vec<(usize, i64)>> = vec![Vec::new(); num_nodes];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty travel cost = cost
        // Bidirectional
        adj_empty[u].push((v, cost));
        adj_empty[v].push((u, cost));

        // Carrying travel cost = cost * tax
        let carry_cost = cost * tax;
        // Bidirectional
        adj_carry[u].push((v, carry_cost));
        adj_carry[v].push((u, carry_cost));
    }

    // 2. Calculate All-Pairs Shortest Paths (APSP)

    // DistEmpty[i][j]: Shortest path cost i -> j without apples
    let mut dist_empty: Vec<Vec<i64>> = vec![vec![0; num_nodes]; num_nodes];
    // DistCarry[i][j]: Shortest path cost i -> j while carrying apples
    let mut dist_carry: Vec<Vec<i64>> = vec![vec![0; num_nodes]; num_nodes];

    for i in 0..num_nodes {
        // Run Dijkstra N times for G_empty
        let distances_empty = dijkstra_n2(num_nodes, &adj_empty, i);
        for j in 0..num_nodes {
            dist_empty[i][j] = distances_empty[j]; // Since paths are undirected, dist[i][j] = dist[j][i]
        }

        // Run Dijkstra N times for G_carry
        let distances_carry = dijkstra_n2(num_nodes, &adj_carry, i);
        for j in 0..num_nodes {
            dist_carry[i][j] = distances_carry[j]; // Since paths are undirected, dist[i][j] = dist[j][i]
        }
    }

    // 3. Determine the minimum cost for each shop i
    let mut ans: Vec<i64> = vec![0; num_nodes];

    for i in 0..num_nodes {
        let price_i = prices[i];
        let mut min_total_cost = price_i; // Initialize with direct purchase cost

        for j in 0..num_nodes {
            if i == j {
                // Already covered by initialization, cost is prices[i]
                continue;
            }

            // Cost calculation: D_empty(i, j) + prices[j] + D_carry(j, i)
            // Since D_empty(j, i) = D_empty(i, j) and D_carry(j, i) = D_carry(i, j)
            let d_empty = dist_empty[i][j];
            let d_carry = dist_carry[i][j];
            let price_j = prices[j];

            // Check for reachability (INF indicates unreachable)
            if d_empty != INF && d_carry != INF {
                // Calculate total cost safely, assuming no overflow for reachable paths
                let total_cost = d_empty + price_j + d_carry;

                if total_cost < min_total_cost {
                    min_total_cost = total_cost;
                }
            }
        }
        ans[i] = min_total_cost;
    }

    ans
}

