/**
 * Helper class for Min Priority Queue implementation for Dijkstra's algorithm.
 * Stores [distance, node].
 */
class PriorityQueue {
    constructor() {
        // Stores [distance, node]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Bubble up element at index i
    _bubbleUp(i) {
        while (i > 0) {
            const parentIndex = Math.floor((i - 1) / 2);
            // Compare distances (index 0)
            if (this.heap[i][0] < this.heap[parentIndex][0]) {
                [this.heap[i], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[i]];
                i = parentIndex;
            } else {
                break;
            }
        }
    }

    // Sink down element at index i
    _sinkDown(i) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * i + 1;
            let rightChildIndex = 2 * i + 2;
            let smallest = i;

            // Compare distances
            if (leftChildIndex <= lastIndex && this.heap[leftChildIndex][0] < this.heap[smallest][0]) {
                smallest = leftChildIndex;
            }
            if (rightChildIndex <= lastIndex && this.heap[rightChildIndex][0] < this.heap[smallest][0]) {
                smallest = rightChildIndex;
            }

            if (smallest !== i) {
                [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
                i = smallest;
            } else {
                break;
            }
        }
    }

    enqueue(distance, node) {
        this.heap.push([distance, node]);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._sinkDown(0);
        return min;
    }
}


/**
 * Runs Dijkstra's algorithm from a specified source node.
 * @param {number} n Number of nodes.
 * @param {Array<Array<[number, number]>>} adj Adjacency list where adj[u] = [[v1, w1], [v2, w2], ...]
 * @param {number} startNode The source node.
 * @returns {Array<number>} An array of shortest distances from startNode to all other nodes.
 */
function dijkstra(n, adj, startNode) {
    const distances = new Array(n).fill(Infinity);
    distances[startNode] = 0;

    const pq = new PriorityQueue();
    // Store [distance, node]
    pq.enqueue(0, startNode);

    while (!pq.isEmpty()) {
        const [d, u] = pq.dequeue();

        if (d > distances[u]) {
            continue;
        }

        for (const [v, weight] of adj[u]) {
            const newDist = distances[u] + weight;

            if (newDist < distances[v]) {
                distances[v] = newDist;
                pq.enqueue(newDist, v);
            }
        }
    }
    return distances;
}


function solve(n, prices, roads) {
    // 1. Build Graph Representations

    // Graph for Empty travel (cost = original cost)
    const adj_empty = Array.from({ length: n }, () => []);

    // Graph for Carrying travel (cost = original cost * tax)
    const adj_carry = Array.from({ length: n }, () => []);

    for (const [u, v, cost, tax] of roads) {
        const carry_cost = cost * tax;

        // Bidirectional edges for Empty travel
        adj_empty[u].push([v, cost]);
        adj_empty[v].push([u, cost]);

        // Bidirectional edges for Carrying travel
        adj_carry[u].push([v, carry_cost]);
        adj_carry[v].push([u, carry_cost]);
    }

    // 2. Calculate All-Pairs Shortest Paths

    // D_E[i][j]: Shortest distance from i to j (Empty)
    // We run Dijkstra N times, once starting at each potential source i.
    const D_E = [];
    for (let i = 0; i < n; i++) {
        D_E.push(dijkstra(n, adj_empty, i));
    }

    // D_C[j][i]: Shortest distance from j to i (Carrying)
    // Since we want Cost(j -> i, carrying), we run Dijkstra N times starting at j.
    // D_C_raw[j][k] = shortest distance from j to k (Carrying).
    const D_C_raw = [];
    for (let j = 0; j < n; j++) {
        D_C_raw.push(dijkstra(n, adj_carry, j));
    }

    // Helper access: D_C[j][i] is the distance from j to i (Carrying)
    const get_D_C = (j, i) => D_C_raw[j][i];


    // 3. Calculate Final Answer for each store i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly
        let min_cost_i = prices[i];

        // Option 2: Travel i -> j -> i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost(i -> j, empty)
            const cost_i_to_j = D_E[i][j];

            // Cost(j -> i, carrying)
            const cost_j_to_i = get_D_C(j, i);

            // If either path is unreachable, skip this j
            if (cost_i_to_j === Infinity || cost_j_to_i === Infinity) {
                continue;
            }

            // Total Cost = Travel_Empty(i->j) + Price[j] + Travel_Carry(j->i)
            // Note: We must use BigInt if intermediate sums exceed 2^53 - 1, but based on constraints 
            // (max cost ~ 10^14), standard JS Number type (up to 9 * 10^15) should suffice.
            const total_cost = cost_i_to_j + prices[j] + cost_j_to_i;

            if (total_cost < min_cost_i) {
                min_cost_i = total_cost;
            }
        }
        ans[i] = min_cost_i;
    }

    return ans;
}
