use std::collections::BinaryHeap;
use std::cmp::Reverse;

// Define a large constant for infinity, sufficient for costs up to 10^14
const INF: i64 = 1_000_000_000_000_000_000;

// Helper structure for Dijkstra's priority queue
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement Ord and PartialOrd to make BinaryHeap act as a Min-Heap based on cost
impl Ord for State {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        other.cost.cmp(&self.cost) // Reversed comparison for min-heap
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}


/// Runs Dijkstra's algorithm from a single source node.
/// Returns an array where dist[i] is the shortest distance from source to i.
fn dijkstra(n: usize, adj: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
    let mut dist = vec![INF; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position }) = heap.pop() {
        // If we found a shorter path already, skip this outdated entry
        if cost > dist[position] {
            continue;
        }

        for &(neighbor, weight) in &adj[position] {
            let new_cost = cost + weight;
            if new_cost < dist[neighbor] {
                dist[neighbor] = new_cost;
                heap.push(State { cost: new_cost, position: neighbor });
            }
        }
    }
    dist
}

fn solve(n_i64: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n = n_i64 as usize;

    // Adjacency lists for Empty travel (G_E) and Carrying travel (G_C)
    let mut adj_e: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];
    let mut adj_c: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];

    // 1. Graph Construction
    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty Travel (G_E): Weight = cost
        adj_e[u].push((v, cost));
        adj_e[v].push((u, cost));

        // Carrying Travel (G_C): Weight = cost * tax
        // Ensure multiplication doesn't overflow i64 if cost or tax were larger, but here max is 10^9 * 100 = 10^11, safe for i64.
        let carry_cost = cost * tax;
        adj_c[u].push((v, carry_cost));
        adj_c[v].push((u, carry_cost));
    }

    // 2. Shortest Path Calculation (APSP equivalent using N runs of Dijkstra)

    // Dist_E[i][j] = D_empty(i, j)
    let mut dist_e: Vec<Vec<i64>> = vec![vec![0; n]; n];
    for i in 0..n {
        let distances = dijkstra(n, &adj_e, i);
        for j in 0..n {
            dist_e[i][j] = distances[j];
        }
    }

    // Dist_C[i][j] = D_carry(i, j)
    let mut dist_c: Vec<Vec<i64>> = vec![vec![0; n]; n];
    for i in 0..n {
        let distances = dijkstra(n, &adj_c, i);
        for j in 0..n {
            dist_c[i][j] = distances[j];
        }
    }

    // 3. Final Calculation
    let mut ans = vec![0; n];

    for i in 0..n {
        // Option 1: Buy directly at store i
        let mut min_cost = prices[i];

        // Option 2: Travel i -> j (empty), buy at j, travel j -> i (carrying)
        for j in 0..n {
            if i == j {
                continue; 
            }

            // D_empty(i, j) is shortest path from i to j (empty)
            let travel_to_j = dist_e[i][j];

            // D_carry(j, i) is shortest path from j to i (carrying)
            // Since graphs are undirected, D_carry(j, i) = D_carry(i, j)
            let travel_back_from_j = dist_c[i][j]; 

            // Check if paths exist
            if travel_to_j != INF && travel_back_from_j != INF {
                // Total Cost = Travel(i->j, empty) + Price(j) + Travel(j->i, carrying)
                let total_cost = travel_to_j + prices[j] + travel_back_from_j;

                if total_cost < min_cost {
                    min_cost = total_cost;
                }
            }
        }
        ans[i] = min_cost;
    }

    ans
}

