use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Define a structure for the state in Dijkstra's algorithm
#[derive(Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement Ord and PartialOrd manually to make BinaryHeap act as a MinHeap
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the reversal: we want the lowest cost to have the highest priority
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

const INF: i64 = 1_000_000_000_000_000_000; // A sufficiently large value

fn dijkstra(n: usize, adj: &[Vec<(usize, i64)>], start_node: usize) -> Vec<i64> {
    let mut dist = vec![INF; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position }) = heap.pop() {
        // If we found a shorter path already, skip
        if cost > dist[position] {
            continue;
        }

        for &(neighbor, weight) in &adj[position] {
            let new_cost = cost + weight;
            if new_cost < dist[neighbor] {
                dist[neighbor] = new_cost;
                heap.push(State { cost: new_cost, position: neighbor });
            }
        }
    }
    dist
}


fn solve(n: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n_usize = n as usize;

    // 1. Build adjacency lists
    // adj_empty: stores edge costs for traveling without apples
    let mut adj_empty: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n_usize];
    // adj_carry: stores edge costs for traveling with apples (cost * tax)
    let mut adj_carry: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n_usize];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty travel costs (u <-> v)
        adj_empty[u].push((v, cost));
        adj_empty[v].push((u, cost));

        // Carrying travel costs (u <-> v)
        // Ensure multiplication handles potential overflow if intermediate steps were huge, 
        // but since cost <= 10^9 and tax <= 100, cost * tax <= 10^11, fitting in i64.
        let carry_cost = cost * tax;
        adj_carry[u].push((v, carry_cost));
        adj_carry[v].push((u, carry_cost));
    }

    // 2. Calculate APSP using N runs of Dijkstra
    // DistE[i][j] = minimum cost from i to j (Empty)
    let mut dist_e = vec![vec![INF; n_usize]; n_usize];
    // DistC[i][j] = minimum cost from i to j (Carry)
    let mut dist_c = vec![vec![INF; n_usize]; n_usize];

    // Calculate DistE
    for i in 0..n_usize {
        let results = dijkstra(n_usize, &adj_empty, i);
        for j in 0..n_usize {
            dist_e[i][j] = results[j];
        }
    }

    // Calculate DistC
    for i in 0..n_usize {
        let results = dijkstra(n_usize, &adj_carry, i);
        for j in 0..n_usize {
            dist_c[i][j] = results[j];
        }
    }

    // 3. Determine the minimum cost for each shop i
    let mut ans = Vec::with_capacity(n_usize);

    for i in 0..n_usize {
        // Option 1: Buy directly at i
        let mut min_cost = prices[i];

        // Option 2: Travel i -> j (empty), buy at j, return j -> i (carrying)
        for j in 0..n_usize {
            // We need DistE(i, j) + prices[j] + DistC(j, i)

            // Since graphs are undirected, DistC(j, i) = DistC(i, j)
            // DistE(i, j) is already calculated.

            let cost_empty_ij = dist_e[i][j];
            let cost_carry_ji = dist_c[j][i]; // Using j->i path

            // Check for reachability before summing
            if cost_empty_ij != INF && cost_carry_ji != INF {
                // Calculate total cost: Path i->j + Price[j] + Path j->i
                let total_cost = cost_empty_ij + prices[j] + cost_carry_ji;

                if total_cost < min_cost {
                    min_cost = total_cost;
                }
            }
        }
        ans.push(min_cost);
    }

    ans
}

