use std::collections::{BinaryHeap, VecDeque};
use std::cmp::Ordering;

// Define a structure for priority queue elements: (cost, node_index)
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement Ord and PartialOrd for min-heap behavior (BinaryHeap is a max-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice that we reverse the comparison to make it a min-heap based on cost
        other.cost.cmp(&self.cost)
            .then_with(|| self.position.cmp(&other.position))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}


// Dijkstra's Algorithm implementation
// Returns a vector of distances from the source node to all other nodes.
fn dijkstra(n: usize, adj: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
    const INF: i64 = 1_000_000_000_000_000_000; // Sufficiently large infinity

    let mut dist: Vec<i64> = vec![INF; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position }) = heap.pop() {
        if cost > dist[position] {
            continue;
        }

        for &(neighbor, weight) in &adj[position] {
            let new_cost = cost + weight;
            if new_cost < dist[neighbor] {
                dist[neighbor] = new_cost;
                heap.push(State { cost: new_cost, position: neighbor });
            }
        }
    }
    dist
}


fn solve(n: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let N = n as usize;
    const INF: i64 = 1_000_000_000_000_000_000;

    // Graph setup: Adjacency lists for Empty and Carrying travel costs
    // adj_empty[u] stores (v, cost)
    let mut adj_empty: Vec<Vec<(usize, i64)>> = vec![vec![]; N];
    // adj_carry[u] stores (v, cost * tax)
    let mut adj_carry: Vec<Vec<(usize, i64)>> = vec![vec![]; N];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty travel costs (C)
        // Bidirectional: u <-> v
        adj_empty[u].push((v, cost));
        adj_empty[v].push((u, cost));

        // Carrying travel costs (C * T)
        let carrying_cost = cost * tax;
        // Bidirectional: u <-> v
        adj_carry[u].push((v, carrying_cost));
        adj_carry[v].push((u, carrying_cost));
    }

    // Step 1 & 2: Calculate APSP for Empty travel
    // D_empty[i][j] = Shortest path from i to j when empty
    let mut d_empty: Vec<Vec<i64>> = vec![vec![0; N]; N];
    for i in 0..N {
        d_empty[i] = dijkstra(N, &adj_empty, i);
    }

    // Step 1 & 2: Calculate APSP for Carrying travel
    // D_carry[j][i] = Shortest path from j to i when carrying
    // We run Dijkstra starting at j on G_carry.
    let mut d_carry: Vec<Vec<i64>> = vec![vec![0; N]; N];
    for j in 0..N {
        let distances_from_j = dijkstra(N, &adj_carry, j);
        for i in 0..N {
            d_carry[j][i] = distances_from_j[i];
        }
    }

    // Step 3: Calculate the minimum cost for each store i
    let mut ans: Vec<i64> = Vec::with_capacity(N);

    for i in 0..N {
        // Option 1: Buy directly
        let direct_cost = prices[i];

        // Option 2: Detour via store j
        let mut min_detour_cost = INF;

        for j in 0..N {
            // Cost = Empty(i -> j) + Prices[j] + Carrying(j -> i)

            let travel_empty_ij = d_empty[i][j];
            let travel_carry_ji = d_carry[j][i];

            // Check if both paths exist
            if travel_empty_ij != INF && travel_carry_ji != INF {
                // Calculate total detour cost. Ensure no overflow before comparison if intermediate sums were large, 
                // but since individual costs are <= 10^12, the sum fits in i64 (approx 2*10^12).
                let detour_cost = travel_empty_ij + prices[j] + travel_carry_ji;
                min_detour_cost = min_detour_cost.min(detour_cost);
            }
        }

        // Final answer is the minimum of direct purchase and best detour
        let final_cost = direct_cost.min(min_detour_cost);
        ans.push(final_cost);
    }

    ans
}

