    const adj_carry = Array.from({ length: n }, () => []);

    for (const [u, v, cost, tax] of roads) {
        const carry_cost = cost * tax;

        // Bidirectional edges for Empty travel
        adj_empty[u].push([v, cost]);
        adj_empty[v].push([u, cost]);

        // Bidirectional edges for Carrying travel
        adj_carry[u].push([v, carry_cost]);
        adj_carry[v].push([u, carry_cost]);
    }

    // 2. Calculate All-Pairs Shortest Paths

    // D_E[i][j]: Shortest distance from i to j (Empty)
    // We run Dijkstra N times, once starting at each potential source i.
    const D_E = [];
    for (let i = 0; i < n; i++) {
        D_E.push(dijkstra(n, adj_empty, i));
    }

    // D_C[j][i]: Shortest distance from j to i (Carrying)
    // Since we want Cost(j -> i, carrying), we run Dijkstra N times starting at j.
    // D_C_raw[j][k] = shortest distance from j to k (Carrying).
    const D_C_raw = [];
    for (let j = 0; j < n; j++) {
        D_C_raw.push(dijkstra(n, adj_carry, j));
    }

    // Helper access: D_C[j][i] is the distance from j to i (Carrying)
    const get_D_C = (j, i) => D_C_raw[j][i];


    // 3. Calculate Final Answer for each store i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly
        let min_cost_i = prices[i];

        // Option 2: Travel i -> j -> i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost(i -> j, empty)
            const cost_i_to_j = D_E[i][j];

            // Cost(j -> i, carrying)
            const cost_j_to_i = get_D_C(j, i);

            // If either path is unreachable, skip this j
            if (cost_i_to_j === Infinity || cost_j_to_i === Infinity) {
                continue;
            }

            // Total Cost = Travel_Empty(i->j) + Price[j] + Travel_Carry(j->i)
            // Note: We must use BigInt if intermediate sums exceed 2^53 - 1, but based on constraints 
            // (max cost ~ 10^14), standard JS Number type (up to 9 * 10^15) should suffice.
            const total_cost = cost_i_to_j + prices[j] + cost_j_to_i;

            if (total_cost < min_cost_i) {
                min_cost_i = total_cost;
            }
        }
        ans[i] = min_cost_i;
    }

    return ans;
}
